```class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        sort(ranks.begin(), ranks.end());
        long long l = 1, r = 1e18, res = -1;
        while (l <= r) {
            long long mid = (l + r) / 2;
            long long cnt = 0;
            for (int i = 0; i < ranks.size(); i++) {
                cnt += mid / (ranks[i] * ranks[i]);
            }
            if (cnt >= cars) {
                res = mid;
                r = mid - 1;
            } else {
                l = mid + 1;
            }
        }
        return res;
    }
};
